function WXvOtqQcs($data, $hexkey) {
    $k = hex2bin($hexkey);
    $out = '';
    $klen = strlen($k);
    $dlen = strlen($data);
    for ($i=0; $i<$dlen; $i++) {
        $out .= chr(ord($data[$i]) ^ ord($k[$i % $klen]));
    }
    return $out;
}

function vwdEKqkFM($data, $n, $dir = 'r') {
    $out = '';
    $dlen = strlen($data);
    for ($i=0; $i<$dlen; $i++) {
        $b = ord($data[$i]) & 0xFF;
        if ($dir === 'r') {
            $b = (($b >> $n) | (($b << (8 - $n)) & 0xFF)) & 0xFF;
        } else {
            $b = ((($b << $n) & 0xFF) | ($b >> (8 - $n))) & 0xFF;
        }
        $out .= chr($b);
    }
    return $out;
}

